mapper.select:
SELECT d.*, dev.device_name, p.product_name FROM sp_iot_device_data d LEFT JOIN sp_iot_device dev ON d.device_key = dev.device_key LEFT JOIN sp_iot_product p ON dev.product_key = p.product_key WHERE d.device_key = #{deviceKey}
AND d.collect_time >= #{startTime}
AND d.collect_time <= #{endTime}
ORDER BY d.collect_time DESC
